initScript:
const managerBase = new URL('.', location.href).pathname.replace(/\/$/, '');
const apiBase = managerBase + '/api/dir';
const baseDir = '/.temp';
const namedTestDir = 'api-dir-named';
return {
  apiBase, baseDir, namedTestDir,
  createDirUrl: apiBase + '/create_dir.php',
  scanDirUrl: apiBase + '/scan_dir.php',
  renameDirUrl: apiBase + '/rename_dir.php',
  deleteDirUrl: apiBase + '/delete_dir.php',
  message: 'init done'
};

tests.scriptText:
const t1 = await utils.postForm(createDirUrl, { dir: baseDir });
const m1 = t1.match(/\[(.+?)\/\]/);
assert(m1 && m1[1], 'create(default): parse fail');
const t2 = await utils.postForm(createDirUrl, { dir: baseDir, name: namedTestDir });
const m2 = t2.match(/\[(.+?)\/\]/);
assert(m2 && m2[1], 'create(named): parse fail');
return { defaultDirPath: m1[1], namedDirPath: m2[1], message: 'created default + named' };

const text = await utils.postForm(scanDirUrl, { path: baseDir });
const arr = JSON.parse(text || '[]');
assert(Array.isArray(arr), 'scan dir: result not array');
assert(arr.includes(utils.basename(defaultDirPath)), 'scan dir: default missing');
assert(arr.includes(utils.basename(namedDirPath)), 'scan dir: named missing');
return { message: 'scan ok' };

const text = await utils.postForm(renameDirUrl, { path: namedDirPath, name: 'api-dir-renamed' });
const m = text.match(/to \[(.+?)\/\]/);
assert(m && m[1], 'rename dir: parse fail');
const arr = JSON.parse((await utils.postForm(scanDirUrl, { path: baseDir })) || '[]');
assert(Array.isArray(arr), 'rename dir: scan result not array');
assert(!arr.includes(utils.basename(namedDirPath)), 'rename dir: old name still exists');
assert(arr.includes(utils.basename(m[1])), 'rename dir: new name missing');
return { renamedDirPath: m[1], message: 'renamed + verified=' + m[1] };

await utils.postForm(deleteDirUrl, { path: defaultDirPath });
await utils.postForm(deleteDirUrl, { path: renamedDirPath });
const arr = JSON.parse((await utils.postForm(scanDirUrl, { path: baseDir })) || '[]');
assert(Array.isArray(arr), 'delete dir: scan result not array');
assert(!arr.includes(utils.basename(defaultDirPath)), 'delete dir: default still exists');
assert(!arr.includes(utils.basename(renamedDirPath)), 'delete dir: renamed still exists');
return { message: 'deleted + verified' };
